    try testing.expectEqualStrings("type", std.mem.trim(u8, result.object.get("interaction").?.object.get("action_results").?.array.items[0].object.get("action_type").?.string, " \n\r\t"));
    try testing.expectEqual(0, result.object.get("interaction").?.object.get("action_results").?.array.items[0].object.get("action_index").?.integer);
}

test "interact_wait_selector" {
    // Wait for a CSS selector that exists on the page
    suppress_abort();
    var gpa: std.heap.DebugAllocator(.{}) = .init;
    defer _ = gpa.deinit();
    const allocator = gpa.allocator();

    const url = if (std.c.getenv("MOCK_SERVER_INTERACT_WAIT_SELECTOR")) |_pf| try std.fmt.allocPrint(allocator, "{s}", .{std.mem.span(_pf)}) else try std.fmt.allocPrint(allocator, "{s}/fixtures/interact_wait_selector", .{if (std.c.getenv("MOCK_SERVER_URL")) |v| std.mem.span(v) else "http://localhost:8080"});
    defer allocator.free(url);
    const _result_json = try kreuzcrawl.interact("{\"browser\":{\"mode\":\"always\"}}", url, "[{\"selector\":\"#content\",\"type\":\"wait\"}]");
    defer std.heap.c_allocator.free(_result_json);
    const _wrapped_json = try std.fmt.allocPrint(allocator, "{{\"interaction\":{s}}}", .{_result_json});
    defer allocator.free(_wrapped_json);
    var _parsed = try std.json.parseFromSlice(std.json.Value, allocator, _wrapped_json, .{});
    defer _parsed.deinit();
    const result = &_parsed.value;
    try testing.expectEqual(true, result.object.get("interaction").?.object.get("action_results").?.array.items[0].object.get("success").?.bool);
    try testing.expectEqualStrings("wait", std.mem.trim(u8, result.object.get("interaction").?.object.get("action_results").?.array.items[0].object.get("action_type").?.string, " \n\r\t"));
    try testing.expectEqual(0, result.object.get("interaction").?.object.get("action_results").?.array.items[0].object.get("action_index").?.integer);
}
